import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    public void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        String userInput = request.getParameter("input");
        String sanitizedInput = sanitizeInput(userInput);

        out.println("<html>");
        out.println("<head><title>XSS Fixed Page</title></head>");
        out.println("<body>");
        out.println("<h1>User Input: " + sanitizedInput + "</h1>"); // Safe code - Sanitized input displayed
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeInput(String input) {
        // Implement proper encoding to prevent XSS attacks
        return input != null ? org.apache.commons.text.StringEscapeUtils.escapeHtml4(input) : "";
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
